        graphics2D.setRenderingHint(RenderingHints.KEY_INTERPOLATION, interpolationValue);
        graphics2D.setRenderingHint(RenderingHints.KEY_ALPHA_INTERPOLATION, RenderingHints.VALUE_ALPHA_INTERPOLATION_QUALITY);
